head.script:
scwin.sLoUpperLobranCd;
scwin.sUserClsCd;

/**
 * event
 * @name onpageload
 * @description 화면로딩시
 */
scwin.onpageload = function () {
    scwin.sUserId = $c.data.getMemInfo("userId");
    scwin.sUserClsCd = $c.data.getMemInfo("userClsCd") ?? "";
    scwin.sClntNo = $c.data.getMemInfo("clntNo") ?? "";
    scwin.sClntNm = $c.data.getMemInfo("clntNm") ?? "";

    //  loUpperLobranCd // 물류상위점소코드
    /*
    사용자 구분(그룹코드:ZZ010)
    01:그룹사
    02:협력업체&고객
    03:선사
    04:화주
    05:자가운송업체
    */
    //물류상위점소코드:  loUpperLobranCd
    scwin.sLoUpperLobranCd = $c.data.getMemInfo("loUpperLobranCd") ?? "";

    let param = $c.data.getParameter();
    let lobranCd = param.lobranCd ?? "";
    scwin.wrkPlCd = param.wrkPlCd ?? "";
    scwin.lineCd = param.lineCd ?? "";

    if (!$c.gus.cfIsNull(lobranCd)) {
        scwin.sLoUpperLobranCd = lobranCd;
    }
    scwin.currentDate = $c.date.getServerDateTime("yyyyMMdd");

    const codeOptions = [
        { grpCd: "OP171", compID: "acb_fullEmptyClsCd" },
        { grpCd: "OP101", compID: "acb_siz" },
        { grpCd: "OP102", compID: "acb_typ" },
        { grpCd: "OP197", compID: "acb_crryInOutCd" },
        { grpCd: "SD060", compID: "acb_impExpClsCd" },
        { grpCd: "SD113", compID: "acb_odrKndCd" },
    ];
    $c.data.setCommonCode(codeOptions, scwin.onLoadCommonCode);

    $c.sbm.execute(sbm_retriveLobranCd);

    ed_stDt.setValue(scwin.currentDate);
    ed_endDt.setValue(scwin.currentDate);
};

/**
 * method
 * @name onUdcCompleted
 * @description
 */
scwin.onUdcCompleted = function () {
    if (scwin.sUserClsCd != "01") {  //사용자가 협력업체 일때
        //개인화 문제로 그리드 2개 만들어서 보이는것 교체
        grp_title1.hide();
        grp_title2.show();
        grd_section1.hide();
        grd_section2.show();

        ed_shpCo.setValue(scwin.sClntNo);
        ed_shpNm.setValue(scwin.sClntNm);
        ed_shpCo.setDisabled(true);
        ed_shpNm.setDisabled(true);
        $c.gus.cfDisableObjects([btn_shpCd]);

        scwin.f_setLine();
    }
};

/**
 * method
 * @name onLoadCommonCode
 * @description 공통코드 조회 콜백
 */
scwin.onLoadCommonCode = function () {
    acb_fullEmptyClsCd.addItem("전체", "", null, 0);
    acb_fullEmptyClsCd.setValue("");
    acb_siz.addItem("전체", "", null, 0);
    acb_siz.setValue("");
    acb_typ.addItem("전체", "", null, 0);
    acb_typ.setValue("");
    acb_crryInOutCd.addItem("전체", "", null, 0);
    acb_crryInOutCd.setValue("");
    acb_impExpClsCd.addItem("전체", "", null, 0);
    acb_impExpClsCd.setValue("");
    let dlt_odrKndCd = $c.gus.object("dlt_commonCodeSD113");
    $c.data.dataListFilter(dlt_odrKndCd, "fltrCd1 == '" + DsConstants.ODR_CNTR + "' && fltrCd3 == '1'");
    acb_odrKndCd.addItem("전체", "", null, 0);
    acb_odrKndCd.setValue("");
};

/**
 * method
 * @name f_FieldClear
 * @description 조회 조건 초기화
 */
scwin.f_FieldClear = function () {
    $c.gus.cfInitObjects(grp_cond, [])
    ed_stDt.setValue(scwin.currentDate);
    ed_endDt.setValue(scwin.currentDate);

    acb_con_branCd.setValue(scwin.sLoUpperLobranCd);
    scwin.acb_con_branCd_onviewchange();

    if (scwin.sUserClsCd != "01") {  //사용자가 협력업체 일때
        ed_shpCo.setValue(scwin.sClntNo);
        ed_shpNm.setValue(scwin.sClntNm);
        ed_shpCo.setDisabled(true);
        ed_shpNm.setDisabled(true);
        $c.gus.cfDisableObjects([btn_shpCd]);

        scwin.f_setLine();
    }
};

/**
 * method
 * @name f_Retrieve
 * @description 조회
 */
scwin.f_Retrieve = async function () {
    let valInfo = [
        { id: "stDt", label: "반출입 시작일자", mandatory: true, minLength: 8, maxLength: 8 },
        { id: "endDt", label: "반출입 종료일자", mandatory: true, minLength: 8, maxLength: 8 },
    ];
    if (!$c.data.validateGroup(grp_cond, valInfo)) {
        return;
    }

    const stHh = ed_stHh.getValue().replace(":", "");
    if (stHh != "" && stHh.length < 4) {
        await $c.gus.cfAlertMsg("시작시간이 잘못되었습니다.");
        return;
    }
    const endHh = ed_endHh.getValue().replace(":", "");
    if (endHh != "" && endHh.length < 4) {
        await $c.gus.cfAlertMsg("종료시간이 잘못되었습니다.");
        return;
    }

    if (ed_stDt.getValue() > ed_endDt.getValue()) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_039).then(() => ed_endDt.focus());
        return;
    }

    dma_queryCondition.setJSON({
        "lobranCd": acb_con_branCd.getValue(),           //점소
        "wrkPlCd": acb_wrkPlCd.getValue(),               // 작업장
        "vsslCd": ed_vsslCd.getValue(),                       // 선박
        "portcnt": ed_portCnt.getValue(),                   // 항차
        "lineCd": acb_lineCd.getValue(),                 // 라인코드
        "shpCoClntNo": ed_shpCo.getValue(),                   // 선사
        "crryinoutClsCd": acb_crryInOutCd.getValue(),    // 반출입구분
        "impExpClsCd": acb_impExpClsCd.getValue(),       // 수출입구분
        "fullEmptyClsCd": acb_fullEmptyClsCd.getValue(), // F/E
        "cntrSizCd": acb_siz.getValue(),                 // 사이즈
        "cntrTypCd": acb_typ.getValue(),                 // 타입
        "odrKndCd": acb_odrKndCd.getValue(),             // 오더종류
        "stHh": stHh,                           // 시작시간
        "endHh": endHh,                         // 종료시간
        "bilgClntNo": ed_bilgClntNo.getValue(),
    });
    $c.sbm.execute(sbm_retrieveDailyCntrMove);
};

/**
 * method
 * @name f_runExcel
 * @description Excel
 * @param
 */
scwin.f_runExcel = async function () {
    if (ds_Grid1.getRowCount()) {
        let cfrm = await $c.win.confirm("EXCEL로 다운로드 받으시겠습니까?");
        if (cfrm) {
            $c.data.downloadGridViewExcel(gr_Grid1, { fileName: 'Daily Cntr Movement.xlsx', sheetName: 'Daily Cntr Movement' });
        }
    } else {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_002);
    }
};

/**
 * method
 * @name f_runExcel2
 * @description Excel
 * @param
 */
scwin.f_runExcel2 = async function () {
    if (ds_Grid2.getRowCount()) {
        let cfrm = await $c.win.confirm("EXCEL로 다운로드 받으시겠습니까?");
        if (cfrm) {
            $c.data.downloadGridViewExcel(gr_Grid2, { fileName: 'Daily Cntr Movement.xlsx', sheetName: 'Daily Cntr Movement' });
        }
    } else {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_002);
    }
};

/**
 * method
 * @name f_openCommonPopUp
 * @description 공통 Popup 처리 : Gubun Code 에 따른 공통 Popup 을 호출한다.
 * @param {Number} disGubun
 * @param {String} pCode
 * @param {String} pName
 * @param {String} pClose
 * @param {String} pAllSearch
 */
scwin.f_openCommonPopUp = function (disGubun, pCode, pName, pClose, pAllSearch) {
    switch (disGubun) {
        case 3:
            // 선사 팝업
            udc_shpCode.cfCommonPopUp(scwin.udc_shpCode_popup_callback, pCode, pName, pClose, null, null, null, null, 'SHP', null, null, null, null, null, pAllSearch, "선사,선사코드,선사명", "F");
            break;

        case 4:
            // 선박
            udc_vsslCode.cfCommonPopUp(scwin.udc_vsslCode_popup_callback, pCode, pName, pClose, null, null, null, null, null, null, null, null, null, null, pAllSearch, "선사,선사코드,선사명", "F");
            break;

        case 5:
            // 청구처
            udc_bilgClntCode.cfCommonPopUp(scwin.udc_bilgClntCode_popup_callback, pCode, pName, pClose, null, null, null, null, null, null, null, null, null, null, pAllSearch, "청구 거래처,거래처코드,거래처명", "F");
            break;

        default:
            break;
    }
};

/**
 * method
 * @name udc_shpCode_popup_callback
 * @description 팝업 콜백
 * @param {Array} rtnList
 */
scwin.udc_shpCode_popup_callback = function (rtnList) {
    if (rtnList != null) {
        if (rtnList[0] == "N/A") {
            return
        };
        ed_shpCo.setValue(rtnList[0]);    //선사코드
        ed_shpNm.setValue(rtnList[1]);  //선사명
        ed_shpNm.options.hidVal = rtnList[1];  //선사명
    } else {
        ed_shpCo.setValue("");    //선사코드
        ed_shpNm.setValue("");  //선사명
        ed_shpNm.options.hidVal = "";  //선사명
    }
    scwin.f_setLine();
};

/**
 * method
 * @name udc_vsslCode_popup_callback
 * @description 팝업 콜백
 * @param {Array} rtnList
 */
scwin.udc_vsslCode_popup_callback = function (rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_vsslCd, ed_vsslNm, null);
};

/**
 * method
 * @name udc_bilgClntCode_popup_callback
 * @description 팝업 콜백
 * @param {Array} rtnList
 */
scwin.udc_bilgClntCode_popup_callback = function (rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_bilgClntNo, ed_bilgClntNm);
};

/**
 * method
 * @name f_chkOpenCommonPopUp
 * @description 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
 * @param {Object} inObj
 * @param {Object} pairObj
 * @param {Number} disGubun
 * @param {Boolean} isCode
 */
scwin.f_chkOpenCommonPopUp = function (inObj, pairObj, disGubun, isCode) {
    // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj)) {
        return;
    }

    // 짝이 되는 오브젝트의 값 제거
    $c.gus.cfClearPairObj(pairObj);

    // 검색어 세팅
    let pVal = $c.gus.cfGetValue(inObj);

    // inObj가 코드 필드일 경우 팝업
    if (isCode == null || isCode == true) {
        scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'F');
        // inObj가 코드명 필드일 경우 팝업
    } else {
        scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
    }
};

/**
 * method
 * @name f_setLine
 * @description 라인콤보 조회
 */
scwin.f_setLine = function () {
    dma_retrieveLineEachShpCoCdCombo.setJSON({
        sysCd: "LineEBC",
        queryId: "retrieveLineEachShpCoCdCombo",
        param1: scwin.sClntNo,
        param2: scwin.sUserClsCd,
        param3: ed_shpCo.getValue(),
    });
    $c.sbm.execute(sbm_retrieveLineEachShpCoCdCombo);
};

/**
 * method
 * @name f_dateChange
 * @description
 */
scwin.f_dateChange = function () {
    if (ed_endDt.getValue().trim() === "") {
        ed_endDt.setValue(ed_stDt.getValue());
    }
};

/**
 * method
 * @name f_OzReport
 * @description Daily Cntr Movement 발행
 */
scwin.f_OzReport = async function () {
    let valInfo = [
        { id: "stDt", label: "반출입 시작일자", mandatory: true, minLength: 8, maxLength: 8 },
        { id: "endDt", label: "반출입 종료일자", mandatory: true, minLength: 8, maxLength: 8 },
    ];
    if (!$c.data.validateGroup(grp_cond, valInfo)) {
        return;
    }

    if (ed_stDt.getValue() > ed_endDt.getValue()) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_039).then(() => ed_endDt.focus());
        return;
    }

    let reportFile = "/ds/op/wrkrslts/cywrkrslts/op_301_01_47r.ozr";
    if (scwin.sUserClsCd != "01") {  //선사권한일 경우
        reportFile = "/ds/op/wrkrslts/cywrkrslts/op_301_01_47_1r.ozr";
    }
    let conBran = acb_con_branCd.getText().split(":");
    let data = {
        odiName: "op_301_01_47r",
        reportName: reportFile,
        odiParam: {
            odiName: "op_301_01_47r",
            conBranCd: conBran[0].trim(),
            conBranNm: conBran[1].trim() ?? "",
            wrkPlCd: acb_wrkPlCd.getValue() ?? "",
            vsslCd: ed_vsslCd.getValue() ?? "",
            portCnt: ed_portCnt.getValue() ?? "",
            lineCd: acb_lineCd.getValue() ?? "",
            crryInOutCd: acb_crryInOutCd.getValue() ?? "",
            impExpClsCd: acb_impExpClsCd.getValue() ?? "",
            fullEmptyClsCd: acb_fullEmptyClsCd.getValue() ?? "",
            siz: acb_siz.getValue() ?? "",
            typ: acb_typ.getValue() ?? "",
            stDt: ed_stDt.getValue() ?? "",
            endDt: ed_endDt.getValue() ?? "",
            odrKndCd: acb_odrKndCd.getValue() ?? "",
            shpCoClntNo: ed_shpCo.getValue() ?? "",
        },
        viewerParam: {
            "useprogressbar": true, // 프로그레스바 쓸지 말지
            "mode": chb_previewCheck.getValue() == "1" ? "preview" : "export", //preview, print, export
        },
        formParam: {
        }
    };

    let opts = {
        id: "ozReportPopup",
        popupName: "오즈 리포트",
        modal: false,
        type: "browserPopup",
        width: 1000,
        height: 830,
        title: "오즈 리포트"
    };
    await $c.win.openPopup("/ui/cm/zz/ozreportPopup.xml", opts, data);
};

