/**
 * event
 * @name sbm_retrieveDailyCntrMove_submitdone
 * @description
 * @param {Object} e
 */
scwin.sbm_retrieveDailyCntrMove_submitdone = async function (e) {
    if (e.responseJSON?.resultDataSet?.length && e.responseJSON.resultDataSet[0].Code == -1) {
        return;
    }
    let rowCnt = ds_Grid1.getRowCount();
    if (!rowCnt) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_002);
    }
    txt_totalRows.setValue(rowCnt);
    txt_totalRows1.setValue(rowCnt);
    scwin.f_SetDataPut();
};

/**
 * event
 * @name sbm_retriveLobranCd_submitdone
 * @description
 * @param {Object} e
 */
scwin.sbm_retriveLobranCd_submitdone = function (e) {
    if (e.responseJSON?.resultDataSet?.length && e.responseJSON.resultDataSet[0].Code == -1) {
        return;
    }
    ds_branCd.insertJSON(0, [{ col1: "", col2: "전체" }]);
    acb_con_branCd.setValue(scwin.sLoUpperLobranCd);
    scwin.acb_con_branCd_onviewchange();
};

/**
 * event
 * @name acb_con_branCd_onviewchange
 * @description
 * @param {Object} info
 */
scwin.acb_con_branCd_onviewchange = function (info) {
    dma_retriveWrkLobranCd.setJSON({
        sysCd: "CommonEBC",
        queryId: "retriveWrkLobranCd",
        param1: "",
        param2: "",
        param3: acb_con_branCd.getValue(),
    });
    $c.sbm.execute(sbm_retriveWrkLobranCd);
    acb_wrkPlCd.focus();
};

/**
 * event
 * @name sbm_retriveWrkLobranCd_submitdone
 * @description
 * @param {Object} e
 */
scwin.sbm_retriveWrkLobranCd_submitdone = async function (e) {
    if (e.responseJSON?.resultDataSet?.length && e.responseJSON.resultDataSet[0].Code == -1) {
        return;
    }
    ds_wrkPlCd.insertJSON(0, [{ col1: "", col2: "전체" }]);
    acb_wrkPlCd.setValue(scwin.wrkPlCd);
    scwin.acb_wrkPlCd_onviewchange();
    if (!$c.gus.cfIsNull(scwin.wrkPlCd)) {
        await scwin.f_Retrieve();
    }
};

/**
 * event
 * @name acb_wrkPlCd_onviewchange
 * @description
 * @param {Object} info
 */
scwin.acb_wrkPlCd_onviewchange = function (info) {
    dma_retrivecBlockList.setJSON({
        sysCd: "WorkPlaceEachGoodsEBC",
        queryId: "retrivecBlockList",
        param1: acb_wrkPlCd.getValue(),
        param2: "",
        param3: "",
    });
    $c.sbm.execute(sbm_retrivecBlockLis);
};

/**
